public abstract class Shape {
    String color;                          // concrete field

    public Shape(String color) {           // concrete constructor
        this.color = color;
    }

    public abstract double area();         // ABSTRACT: no body
    public abstract double perimeter();    // ABSTRACT: no body

    public void describe() {               // CONCRETE: has body
        System.out.println(color + " shape, area=" + area());
    }
}

public class Circle extends Shape {
    double r;
    public Circle(String color, double r) {
        super(color);
        this.r = r;
    }
    @Override public double area()      { return Math.PI * r * r; }
    @Override public double perimeter() { return 2 * Math.PI * r; }
}

public class Test {
    public static void main(String[] args) {
        // Shape s = new Shape("red");   // COMPILE ERROR: cannot instantiate abstract
        Shape c = new Circle("blue", 5);
        c.describe();   // blue shape, area=78.53981...
    }
}

public interface Drawable {
    // implicitly: public static final
    double PI = 3.14159;

    // implicitly: public abstract
    void draw();
    double getArea();
}

public interface Resizable {
    void resize(double factor);
}

// A class can implement MULTIPLE interfaces
public class Square implements Drawable, Resizable {
    double side;

    public Square(double side) { this.side = side; }

    @Override public void draw() {
        System.out.println("Drawing square with side " + side);
    }
    @Override public double getArea() { return side * side; }
    @Override public void resize(double factor) { side *= factor; }
}

public class Test {
    public static void main(String[] args) {
        Square sq = new Square(4);
        sq.draw();
        sq.resize(2);
        System.out.println(sq.getArea());  // 64.0

        Drawable d = sq;    // upcast to Drawable
        d.draw();           // dynamic dispatch: Square.draw()
        // d.resize(2);     // COMPILE ERROR: resize not in Drawable
    }
}

public interface Greetable {
    String getName();             // abstract: must implement

    default void greet() {        // DEFAULT: inherited automatically
        System.out.println("Hello, I am " + getName());
    }
}

public class Person implements Greetable {
    String name;
    public Person(String name) { this.name = name; }
    @Override public String getName() { return name; }
    // greet() is inherited — no need to override
}

public class FormalPerson implements Greetable {
    String name;
    public FormalPerson(String name) { this.name = name; }
    @Override public String getName() { return name; }
    @Override public void greet() {    // OVERRIDE the default
        System.out.println("Good day. My name is " + getName() + ".");
    }
}

public class Test {
    public static void main(String[] args) {
        new Person("Alice").greet();        // Hello, I am Alice
        new FormalPerson("Bob").greet();    // Good day. My name is Bob.
    }
}

