public interface Vehicle {
    void start();
    void stop();
    String fuelType();
}

// Abstract class implements start/stop but defers fuelType
public abstract class MotorVehicle implements Vehicle {
    String model;
    public MotorVehicle(String model) { this.model = model; }

    @Override public void start() {
        System.out.println(model + " engine starts");
    }
    @Override public void stop() {
        System.out.println(model + " engine stops");
    }
    // fuelType() NOT implemented here — left abstract
}

public class ElectricCar extends MotorVehicle {
    public ElectricCar(String model) { super(model); }
    @Override public String fuelType() { return "Electric"; }
}

public class GasCar extends MotorVehicle {
    public GasCar(String model) { super(model); }
    @Override public String fuelType() { return "Gasoline"; }
}

public class Test {
    public static void main(String[] args) {
        Vehicle v = new ElectricCar("Tesla");
        v.start();
        System.out.println(v.fuelType());
        v.stop();
    }
}
