// Design a mini payment system:
//
// Interface: Taxable
//   - double TAX_RATE = 0.15  (constant)
//   - double calculateTax(double amount)  (abstract)
//
// Abstract class: Payment implements Taxable
//   - double amount
//   - constructor Payment(double amount)
//   - abstract String paymentMethod()
//   - concrete void processPayment() that prints:
//     "Processing [paymentMethod()] payment of [amount]"
//     "Tax: [calculateTax(amount)]"
//     "Total: [amount + calculateTax(amount)]"
//
// Concrete class: CreditCard extends Payment
//   - String cardType
//   - Override paymentMethod() → return "Credit Card (" + cardType + ")"
//   - Override calculateTax(amount) → return amount * TAX_RATE
//
// Concrete class: Cash extends Payment
//   - Override paymentMethod() → return "Cash"
//   - Override calculateTax(amount) → return 0.0  (cash is tax-free)
//
// Demo: process CreditCard(500, "Visa") and Cash(200)

sections.solution:
public interface Taxable {
    double TAX_RATE = 0.15;   // public static final
    double calculateTax(double amount);
}

public abstract class Payment implements Taxable {
    double amount;

    public Payment(double amount) {
        this.amount = amount;
    }

    public abstract String paymentMethod();

    // Template method — calls abstract methods
    public void processPayment() {
        double tax   = calculateTax(amount);
        double total = amount + tax;
        System.out.printf("Processing %s payment of %.2f%n",
                          paymentMethod(), amount);
        System.out.printf("Tax: %.2f%n", tax);
        System.out.printf("Total: %.2f%n", total);
    }
}

public class CreditCard extends Payment {
    String cardType;

    public CreditCard(double amount, String cardType) {
        super(amount);
        this.cardType = cardType;
    }

    @Override
    public String paymentMethod() {
        return "Credit Card (" + cardType + ")";
    }

    @Override
    public double calculateTax(double amount) {
        return amount * TAX_RATE;     // use interface constant
    }
}

public class Cash extends Payment {
    public Cash(double amount) { super(amount); }

    @Override
    public String paymentMethod() { return "Cash"; }

    @Override
    public double calculateTax(double amount) { return 0.0; }
}

public class PaymentSystem {
    public static void main(String[] args) {
        Payment[] payments = {
            new CreditCard(500, "Visa"),
            new Cash(200)
        };
        for (Payment p : payments) {
            p.processPayment();
            System.out.println("---");
        }
    }
}
// Processing Credit Card (Visa) payment of 500.00
// Tax: 75.00
// Total: 575.00
// ---
// Processing Cash payment of 200.00
// Tax: 0.00
// Total: 200.00
// ---
